import { canRedo as redoAvailable, canUndo as undoAvailable, won as gameWonState } from './grid';
import { writable } from 'svelte/store';

/**
 * 游戏是否处于暂停状态。
 *
 * 这是纯 UI 状态，不属于领域对象本身，所以仍然保留在独立 store 中。
 */
export const gamePaused = writable(true);

/**
 * 透传领域层导出的撤销能力。
 */
export const gameCanUndo = undoAvailable;

/**
 * 透传领域层导出的重做能力。
 */
export const gameCanRedo = redoAvailable;

/**
 * 透传领域层导出的胜利状态。
 */
export const gameWon = gameWonState;
